public class ProxyImage implements Image { private final String filename; private RealImage realImage; public ProxyImage(String f) { this.filename = f; } public void display() { if (realImage == null) { System.out.println("[Proxy] First access - loading..."); realImage = new RealImage(filename); } else { System.out.println("[Proxy] Cached - no load needed."); } realImage.display(); } public String getFilename() { return filename; } }